import { Container, Grid, DialogContent, Button, Stack, ToggleButton, ToggleButtonGroup, Typography, TextField, Link } from '@mui/material';
import { motion } from 'framer-motion';
import { useState } from 'react';
import Lottie from 'react-lottie';
import useSound from 'use-sound';
import { NavLink, NavLink as RouterLink } from 'react-router-dom';

import NFTCard from '../NFTCard';
import { varFadeInUp, DialogAnimate, varZoomInUp } from '../../animate';

import SuccessCheckLottie from '../../../assets/lottie/successCheck.json';
import popDingSound from '../../../assets/sfx/popDing.wav';

const successCheckOptions = {
    loop: false,
    autoplay: true,
    animationData: SuccessCheckLottie,
    background: 'transparent'
};

export default function MyNFTListItem({ items, index }){
    const [playPopDingSound, { stopPopDingSound }] = useSound(popDingSound);

    // LISTING
    const [listingCurrency, setListingCurrency] = useState('BNB');
    const [listingPrice, setListingPrice] = useState(0);
    const [selectedSellNFT, setSelectedSellNFT] = useState('');

    const handleChangeListingPrice = (e) => {
        setListingPrice(e.target.value);
    }
    
    const handleListingCurrency = (event, newListingCurrency) => {
        setListingCurrency(newListingCurrency);
    };

    // EDIT LISTING DIALOG
    const [openEditListingDialog, setOpenEditListingDialog] = useState(false);
    const [openEditListingSuccessDialog, setOpenEditListingSuccessDialog] = useState(false);

    const handleOpenEditListingDialog = (selectedNFT) => {
        const selectedNFTTemp = selectedNFT;

        setSelectedSellNFT(selectedNFTTemp);
        setListingCurrency(selectedNFTTemp.saleData.currency)
        setListingPrice(selectedNFTTemp.saleData.price)

        setOpenEditListingDialog(true);
    }

    const handleCloseSellDialog = () => {
        setOpenEditListingDialog(false);
        setListingCurrency('BNB');
        setListingPrice(0);
    }


    const handleCloseSuccessEditListingDialog = () => {
        setOpenEditListingSuccessDialog(false);
        setOpenEditListingDialog(false);
        setListingCurrency('BNB');
        setListingPrice(0);
    }

    const handleEditListing = () => {
        playPopDingSound();
        setOpenEditListingSuccessDialog(true);
    }

    // REMOVE LISTING
    const [openRemoveListingSuccessDialog, setOpenRemoveListingSuccessDialog] = useState(false);
    
    const handleRemoveListing = () => {
        playPopDingSound();
        setOpenRemoveListingSuccessDialog(true);
        setOpenEditListingDialog(false);
        setListingCurrency('BNB');
        setListingPrice(0);
    }

    const handleCloseRemoveListingDialog = () => {
        setOpenListingDialog(false);
        setOpenRemoveListingSuccessDialog(false);
    }

    // LISTING DIALOG
    const [openListingDialog, setOpenListingDialog] = useState(false);
    const [openListingSuccessDialog, setOpenListingSuccessDialog] = useState(false);

    const handleOpenListingDialog = (selectedNFT) => {
        const selectedNFTTemp = selectedNFT;

        setSelectedSellNFT(selectedNFTTemp);
        setListingCurrency('BNB');
        setListingPrice('');

        setOpenListingDialog(true);
    }

    const handleCloseListingDialog = () => {
        setOpenListingDialog(false);
        setListingCurrency('BNB');
        setListingPrice(0);
    }

    const handleOpenSuccessListingDialog = () => {
        setOpenListingSuccessDialog(true);
    }

    const handleCloseSuccessListingDialog = () => {
        setOpenListingDialog(false);
        setOpenListingSuccessDialog(false);
        setListingCurrency('BNB');
        setListingPrice(0);
    }

    const handleListing = () => {
        playPopDingSound();
        handleOpenSuccessListingDialog();
    }

    return(
        <>
            <Container maxWidth="xl">
                <Grid container spacing={4} alignItems="stretch" direction="row" justifyContent="flex-start" style={{ marginTop: '2rem' }}>
                    {items.map((collection, index) => {
                        if(collection.status === 'owned'){
                            return(
                                <>
                                    <Grid item xs={12} sm={6} md={4} lg={3} xl={3} style={{ marginBottom: '1rem' }}>
                                        <motion.div key={`${index}`} variants={varFadeInUp}>
                                            <NFTCard ownedAction collection={collection} 
                                                handleOpenListingDialog={handleOpenListingDialog}
                                            />
                                        </motion.div>
                                    </Grid>
                                </>
                            )
                        }

                        if(collection.status === 'listed'){
                            return(
                                <>
                                    <Grid item xs={12} sm={6} md={4} lg={3} xl={3} style={{ marginBottom: '1rem' }}>
                                        <motion.div key={`${index}`} variants={varFadeInUp}>
                                            <NFTCard editListingAction collection={collection} 
                                                handleOpenEditListingDialog={handleOpenEditListingDialog} 
                                            />
                                        </motion.div>
                                    </Grid>
                                </>
                            )
                        }

                        if(collection.status === 'sold'){
                            return(
                                <>
                                    <Grid item xs={12} sm={6} md={4} lg={3} xl={3} style={{ marginBottom: '1rem' }}>
                                        <motion.div key={`${index}`} variants={varFadeInUp}>
                                            <NFTCard sold collection={collection}/>
                                        </motion.div>
                                    </Grid>
                                </>
                            )
                        }
                        
                        return '';
                    })}
                </Grid>
            </Container>

            {/* EDIT LISTING DIALOG */}
            <DialogAnimate fullWidth maxWidth="md" open={openEditListingDialog} animate={varZoomInUp}>
                <DialogContent style={{ position: 'relative', zIndex: '3' }}>
                    <Grid spacing={3} container alignItems="stretch" direction="row" justifyContent="flex-start" >
                        <Grid item xs={12} md={12} lg={4} xl={4}> 
                            <NFTCard collection={selectedSellNFT} />
                        </Grid>

                        <Grid item xs={12} md={12} lg={8} xl={8}>
                            <Stack style={{ height: '100%', minHeight: '14rem' }}>
                                <Typography variant="h6" style={{ marginBottom: '0.4rem' }}>
                                    Listing Currency
                                </Typography>

                                <ToggleButtonGroup value={listingCurrency} exclusive onChange={handleListingCurrency}>
                                    <ToggleButton className="listing-currency-toggle listing-currency-bnb" 
                                        value="BNB" style={{ minWidth: '5rem' }}
                                    >
                                        <Stack direction="row" alignItems="center" spacing={1}>
                                            <div>
                                                BNB
                                            </div>
                                            <img src="/static/SHAZU/icons/ic_bnb.svg" alt="" style={{ width: '1rem', height: '1rem', marginLeft: '0.2rem', marginBottom: '0.1rem' }} />
                                        </Stack>
                                    </ToggleButton>
                                    <ToggleButton className="listing-currency-toggle listing-currency-shazu" 
                                        value="SHAZU" style={{ minWidth: '5rem' }}
                                    >
                                        <Stack direction="row" alignItems="center" spacing={1}>
                                            <div>
                                                SHAZU
                                            </div>
                                            <img src="/static/SHAZU/icons/ic_shazu.png" alt="" style={{ width: '1rem', height: '1rem', marginLeft: '0.2rem', marginBottom: '0.1rem' }} />
                                        </Stack>
                                    </ToggleButton>
                                </ToggleButtonGroup>

                                <TextField onChange={handleChangeListingPrice} value={listingPrice} 
                                    color="yellow" variant="standard" 
                                    label={`Price (${listingCurrency})`} type="number" 
                                    className="border-field-input" 
                                    style={{ marginTop: '2rem', maxWidth: '14rem', marginBottom: '2rem' }}
                                />

                                <Stack direction="column" spacing={2}>
                                    <Button onClick={handleEditListing} disabled={!listingPrice} variant="contained" color="purple">
                                        EDIT
                                    </Button>

                                    <Button color="error" onClick={handleRemoveListing} >
                                        Remove Listing
                                    </Button>
                                </Stack>
                            </Stack>
                        </Grid>
                    </Grid>

                    <Stack style={{ marginTop: '2rem' }}>
                        <Button onClick={handleCloseSellDialog} variant="container" style={{ marginLeft: 'auto' }}>
                            Close
                        </Button>
                    </Stack>
                
                </DialogContent>
            </DialogAnimate>

            {/* LISTING DIALOG */}
            <DialogAnimate fullWidth maxWidth="md" open={openListingDialog} animate={varZoomInUp}>
                <DialogContent style={{ position: 'relative', zIndex: '3' }}>
                    <Grid spacing={3} container alignItems="stretch" direction="row" justifyContent="flex-start" >
                        <Grid item xs={12} md={12} lg={4} xl={4}> 
                        <   NFTCard collection={selectedSellNFT} />
                        </Grid>

                        <Grid item xs={12} md={12} lg={8} xl={8}>
                            <Stack style={{ height: '100%', minHeight: '14rem' }}>
                                <Typography variant="h6" style={{ marginBottom: '0.4rem' }}>
                                    Listing Currency
                                </Typography>

                                <ToggleButtonGroup value={listingCurrency} exclusive onChange={handleListingCurrency}>
                                    <ToggleButton className="listing-currency-toggle listing-currency-bnb" 
                                        value="BNB" style={{ minWidth: '5rem' }}
                                    >
                                        <Stack direction="row" alignItems="center" spacing={1}>
                                            <div>
                                                BNB
                                            </div>
                                            <img src="/static/SHAZU/icons/ic_bnb.svg" alt="" style={{ width: '1rem', height: '1rem', marginLeft: '0.2rem', marginBottom: '0.1rem' }} />
                                        </Stack>
                                    </ToggleButton>
                                    <ToggleButton className="listing-currency-toggle listing-currency-shazu" 
                                        value="SHAZU" style={{ minWidth: '5rem' }}
                                    >
                                        <Stack direction="row" alignItems="center" spacing={1}>
                                            <div>
                                                SHAZU
                                            </div>
                                            <img src="/static/SHAZU/icons/ic_shazu.png" alt="" style={{ width: '1rem', height: '1rem', marginLeft: '0.2rem', marginBottom: '0.1rem' }} />
                                        </Stack>
                                    </ToggleButton>
                                </ToggleButtonGroup>

                                <TextField onChange={handleChangeListingPrice} value={listingPrice} 
                                    color="yellow" variant="standard" 
                                    label={`Price (${listingCurrency})`} type="number" 
                                    className="border-field-input" 
                                    style={{ marginTop: '2rem', maxWidth: '14rem', marginBottom: '2rem' }}
                                />

                                <Stack direction="column" spacing={2}>
                                    <Button onClick={handleListing} disabled={!listingPrice} variant="contained" color="purple">
                                        LIST
                                    </Button>
                                </Stack>
                            </Stack>
                        </Grid>
                    </Grid>

                    <Stack style={{ marginTop: '2rem' }}>
                        <Button onClick={handleCloseListingDialog} variant="container" style={{ marginLeft: 'auto' }}>
                            Close
                        </Button>
                    </Stack>
                </DialogContent>
            </DialogAnimate>


            {/* SUCCESS EDIT LISTING DIALOG */}
            <DialogAnimate open={openEditListingSuccessDialog} maxWidth="xs" animate={varZoomInUp} scroll="paper" onClose={handleCloseSuccessEditListingDialog}>
                <DialogContent style={{ textAlign: 'center' }}>
                    <div className="successCheck-lottie-container">
                        <Lottie options={successCheckOptions} isClickToPauseDisabled />
                    </div>
                    <Typography variant="h3">
                        Edit Listing Successful!
                    </Typography>
                    
                    <Link className="no-hover-line" component={NavLink} to={`/marketplace/detail/${selectedSellNFT.id}`}>
                        <Button variant="contained" color="purple" style={{ marginTop: '2rem' }}>
                        See Listing Page
                        </Button>
                    </Link>
                </DialogContent>
            </DialogAnimate>

            {/* SUCCESS REMOVE LISTING DIALOG */}
            <DialogAnimate open={openRemoveListingSuccessDialog} maxWidth="xs" animate={varZoomInUp} scroll="paper" onClose={handleCloseRemoveListingDialog}>
                <DialogContent style={{ textAlign: 'center' }}>
                    <div className="successCheck-lottie-container">
                        <Lottie options={successCheckOptions} isClickToPauseDisabled />
                    </div>
                    <Typography variant="h3">
                        Remove Listing Successful!
                    </Typography>
                </DialogContent>
            </DialogAnimate>

            {/* SUCCESS LISTING DIALOG */}
            <DialogAnimate open={openListingSuccessDialog} maxWidth="xs" animate={varZoomInUp} scroll="paper" onClose={handleCloseSuccessListingDialog}>
                <DialogContent style={{ textAlign: 'center' }}>
                    <div className="successCheck-lottie-container">
                        <Lottie options={successCheckOptions} isClickToPauseDisabled />
                    </div>
                    <Typography variant="h3">
                        Listing Successful!
                    </Typography>
                    
                    <Link className="no-hover-line" component={NavLink} to={`/marketplace/detail/${selectedSellNFT.id}`}>
                        <Button variant="contained" color="purple" style={{ marginTop: '2rem' }}>
                            See Listing Page
                        </Button>
                    </Link>
                </DialogContent>
            </DialogAnimate>
        </>
    )
}